import{_ as a,o as i,c as e,a6 as o}from"./chunks/framework.zaV2WUSU.js";const h=JSON.parse('{"title":"Installing Linux 4 Switch (L4S)","description":"","frontmatter":{},"headers":[],"relativePath":"extras/installing_linux.md","filePath":"extras/installing_linux.md"}'),l={name:"extras/installing_linux.md"};function n(r,t,s,c,p,d){return i(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="installing-linux-4-switch-l4s" tabindex="-1">Installing Linux 4 Switch (L4S) <a class="header-anchor" href="#installing-linux-4-switch-l4s" aria-label="Permalink to “Installing Linux 4 Switch (L4S)”">​</a></h1><p>Linux 4 Switch is a sister project to Switchroot Android--it uses a similar kernel but provides a variety of Linux distributions.</p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p><strong>Have you partitioned your microSD card?</strong></p><p>This page assumes that you&#39;ve followed our guide to partition your microSD card for a Linux setup. If you didn&#39;t do so yet, please follow <a href="./../user_guide/all/partitioning_sd_syscfw">this page</a>.</p></div><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to “Installation”">​</a></h2><p>Click the following link to continue to the official Switchroot documentation for installing an L4S Linux distribution (external link):</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p><a href="https://wiki.switchroot.org/wiki/linux/linux-distributions" class="btn btn-solid">Install a Linux Distribution →</a></p><p><strong>Note:</strong> You can skip the partitioning mentioned in the Switchroot documentation. You already did this during the guide and do <em>not</em> have to do so again.</p></div><p>If you already have Linux fully installed, do not follow this guide, as your current installation would be erased.</p><hr><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p><strong>Need Help?</strong></p><p>Join the <a href="https://discord.gg/N9PPYXjWMY" target="_blank" rel="noreferrer">Switchroot Discord server</a>.</p></div><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p><strong>Looking for Arch?</strong></p><p>Unfortunately, L4S Arch Linux is deprecated following an xorg ABI change that breaks compatibility with the Tegra210 BSP.</p></div><details class="details custom-block"><summary>L4S Project Staff (Android / Linux)</summary><p>This page was made in collaboration with <code>makinbacon21</code> on Discord.</p><p>If you&#39;d like, you can donate to the people who made this project possible using these links.</p><ul><li><p>CTCaer (Linux &amp; Low level developer, hekate maintainer) <a href="https://www.patreon.com/ctcaer" target="_blank" rel="noreferrer">https://www.patreon.com/ctcaer</a></p></li><li><p>Azkali (Linux &amp; Low level developer) <a href="https://www.patreon.com/azkali" target="_blank" rel="noreferrer">https://www.patreon.com/azkali</a></p></li><li><p>gavin_darkglider (Linux &amp; Lakka developer) <a href="https://paypal.me/gavindarkglider" target="_blank" rel="noreferrer">https://paypal.me/gavindarkglider</a></p></li><li><p>ave (Infrastructure &amp; Hosting) <a href="https://patreon.com/aveao" target="_blank" rel="noreferrer">https://patreon.com/aveao</a></p></li></ul></details>',11)])])}const m=a(l,[["render",n]]);export{h as __pageData,m as default};
